// 解析Markdown内容并提取元数据
const content = items[0].json.fileContent;
const lines = content.split('\n');

let title = '';
let description = '';
let tags = [];
let body = '';
let inBody = false;

for (const line of lines) {
  // 提取标题
  if (line.startsWith('# ')) {
    title = line.replace('# ', '');
    continue;
  }

  // 提取描述
  if (line.startsWith('> ')) {
    description = line.replace('> ', '');
    continue;
  }

  // 提取标签
  if (line.startsWith('tags: ')) {
    tags = line.replace('tags: ', '').split(',').map(tag => tag.trim());
    continue;
  }

  // 提取正文
  if (line === '---' || line === '') {
    if (!inBody) {
      inBody = true;
      continue;
    }
  }

  if (inBody && line !== '---') {
    body += line + '\n';
  }
}

return [{
  json: {
    title,
    description,
    tags,
    body,
    originalContent: content
  }
}];

// 格式化内容为知乎文章格式
const item = items[0].json;
const zhihuContent = `# ${item.title}\n\n${item.description}\n\n${item.body}\n\n**标签**: ${item.tags.join(', ')}`;

return [{
  json: {
    ...item,
    zhihuContent
  }
}];

// 格式化内容为掘金文章格式
const item = items[0].json;
const juejinContent = `# ${item.title}\n\n> ${item.description}\n\n${item.body}\n\n## 标签\n${item.tags.map(tag => `- ${tag}`).join('\n')}`;

return [{
  json: {
    ...item,
    juejinContent
  }
}];

// 格式化内容为V2EX帖子格式
const item = items[0].json;
const v2exContent = `## ${item.title}\n\n${item.description}\n\n${item.body}\n\n标签: ${item.tags.join(', ')}`;

return [{
  json: {
    ...item,
    v2exContent
  }
}];

// 记录发布状态
const item = items[0].json;
const timestamp = new Date().toISOString();
const logEntry = {
  timestamp,
  title: item.title,
  platforms: ['知乎', '掘金', 'V2EX'],
  status: 'pending',
  filePath: $input.first().json.filePath
};

// 这里可以添加实际发布逻辑
// 目前只是记录状态
console.log('准备发布文章:', item.title);
console.log('标签:', item.tags);
console.log('内容长度:', item.body.length);

return [{
  json: {
    ...item,
    logEntry,
    message: '文章已格式化完成，准备发布到各平台'
  }
}];
